const data = {};
const challengeState = { step: 'choose', challenge: null, baseline: null, final: null };
let signedInEmail = '';
let phoneConfirmation = null;
const ARCHIVE_OWNER_EMAIL = 'myaeixa@gmail.com';
const beginnerChallenges = [
  {id:'shopping', tag:'Everyday', title:'A practical shopping list', time:'7 minutes', method:'link method', material:['Bread','Milk','Bananas','Eggs','Tomatoes','Pasta','Soap','Tea'], prompt:'Make bread explode milk over bananas, bananas juggle eggs, eggs smash tomatoes, tomatoes dye pasta red, pasta ties up soap, soap slides into tea.'},
  {id:'metric', tag:'Everyday', title:'Useful metric conversions', time:'8 minutes', method:'image association', material:['1 kilometre = 1000 metres','1 metre = 100 centimetres','1 kilogram = 1000 grams','1 litre = 1000 millilitres','0°C = water freezes'], prompt:'Turn each number into a visible object: a thousand tiny metres marching, one metre ruler sprouting 100 centimetre ants, and frozen water at zero.'},
  {id:'uk-capitals', tag:'General knowledge', title:'UK countries and capitals', time:'9 minutes', method:'story method', material:['England — London','Scotland — Edinburgh','Wales — Cardiff','Northern Ireland — Belfast'], prompt:'Picture a lion in London, a thistle at Edinburgh Castle, a red dragon driving a card in Cardiff, and a ringing bell in Belfast.'},
  {id:'planets', tag:'Quick win', title:'The eight planets in order', time:'8 minutes', method:'link method', material:['Mercury','Venus','Earth','Mars','Jupiter','Saturn','Uranus','Neptune'], prompt:'Imagine a thermometer made of mercury falling in love with Venus, landing on Earth, and being painted red by Mars.'},
  {id:'prime-ministers', tag:'Study', title:'A short prime-minister sequence', time:'10 minutes', method:'ordered story', material:['Churchill','Attlee','Churchill','Eden','Macmillan','Douglas-Home'], prompt:'Make each person do an impossible action to the next: Churchill hands a cigar to Attlee, then returns through a giant door into Eden.'}
];
const handbookChapters = ['Observation and attention','Visualisation','Association','Exaggeration and absurdity','Linking method','Story method','Memory palace','Journey method','Peg systems','Major System','PAO','Name and face memory','Number memory','Dates','Vocabulary','Speeches','Spaced retrieval','Active recall','Error correction','Building automaticity','Choosing the correct technique'];

async function boot(){
  for (const n of ['belts','curriculum','starter-major-system','starter-symbols','example-palace','programme','version-archive','major-system-scenes']) data[n]=await fetch(`data/${n}.json`).then(r=>r.json());
  load();
  await initialiseAuth();
  if(!get().majorSystem.length) update(s=>{s.majorSystem=data['starter-major-system'];s.symbols=data['starter-symbols'];s.palaces=[data['example-palace']]});
  cleanupReviews();
  bindNoteDrawer();
  applyTheme();
  applyDesignOverrides();
  route();
  window.addEventListener('hashchange',route);
  window.addEventListener('dojo:data',()=>{badges();applyDesignOverrides();queueCloudSave()});
}

function page(kicker,title,body,action=''){return `<section class="page-hero"><p class="eyebrow">${kicker}</p><h1>${title}</h1>${body}${action}</section>`}
function primaryAction(href,label){return `<a class="button primary-action" href="${href}">${label}</a>`}
function primaryButton(label, action){return `<button class="primary-action" data-action="${action}">${label}</button>`}
function challengeComplete(){return get().firstSuccess?.completed}
function currentDay(){return Math.min(get().profile.currentDay,84)}
function todaySession(){return data.curriculum[currentDay()-1]}

function dashboard(){
  const s=get(), today=todaySession(), reviews=due(), completed=challengeComplete(), avg=mean(s.results.map(x=>x.accuracy));
  const actionHref = !completed ? '#learn' : reviews.length ? '#reviews' : '#train';
  const actionLabel = !completed ? 'Memorise something useful' : reviews.length ? 'Do due review' : `Continue Day ${currentDay()}`;
  const support = completed ? `<section class="quiet-grid"><a class="path-card" href="#train" aria-label="Open current lesson: ${escapeHTML(today.title)}"><h2>Current lesson</h2><p><strong>${escapeHTML(today.title)}</strong></p><p>${escapeHTML(today.goal)}</p><span>Open today’s lesson</span></a><a class="path-card" href="#reviews" aria-label="Open due review queue"><h2>Due review</h2><p>${reviews.length?`${reviews.length} item${reviews.length===1?'':'s'} due now`:'No reviews due right now.'}</p><span>Open things to practise again</span></a><a class="path-card" href="#progress" aria-label="Open progress details"><h2>Progress, briefly</h2><p>${avg?`${avg}% average immediate recall across ${s.results.length} session${s.results.length===1?'':'s'}.`:'Your first score will appear after a recall test.'}</p><span>Open progress details</span></a></section>` : `<section class="empty-state"><h2>No account needed</h2><p>Start as a guest. You will see the list once, try from memory, learn a simple image story, and compare your before-and-after recall.</p></section>`;
  return `${page('Today','Memorise something useful',`<p class="lead">Start with one short, useful success before exploring lessons, scores or advanced tools.</p>`,primaryAction(actionHref,actionLabel))}
  <section class="next-step-panel"><div><p class="eyebrow">Recommended next action</p><h2>${!completed?'Complete your first memory success':reviews.length?'Try to remember before looking':'Today’s lesson'}</h2><p>${!completed?'Choose a beginner challenge, make a no-pressure first attempt, learn one memory method, and see what improves.':`Begin with a short recall attempt, then check and strengthen anything that feels unclear.`}</p><dl class="answer-grid"><div><dt>Why?</dt><dd>${!completed?'So you can feel the method working, not just read about it.':'To keep the route back to the memory strong.'}</dd></div><div><dt>Time</dt><dd>${!completed?'7–10 minutes':`${today.timeLimitMinutes} minutes`}</dd></div><div><dt>After</dt><dd>${!completed?'You will choose one real-life use.':'A quick reminder is scheduled.'}</dd></div></dl></div></section>${support}`;
}

function learn(){
  const done=challengeComplete();
  const nextLinks = done ? `<section class="section-block"><div class="section-heading"><p class="eyebrow">Next</p><h2>Continue learning</h2></div><div class="quiet-grid"><a class="path-card" href="#train"><strong>Daily curriculum</strong><span>84 structured sessions</span></a><a class="path-card" href="#guidance"><strong>Memory Handbook</strong><span>Technique reference after practice</span></a><a class="path-card" href="#reviews"><strong>Things to practise again</strong><span>Spaced review queue</span></a></div></section>` : '';
  if(!done && challengeState.step !== 'choose') return firstSuccessJourney();
  const title = done ? 'Experience the method before the theory' : 'Choose one useful challenge';
  const intro = done ? 'You have completed your first success. Continue with daily practice or open the handbook when you want the theory.' : 'Start with a no-pressure before score, learn one image-story method, then retest from memory.';
  return `${page('Learn',title,`<p class="lead">${intro}</p>`,done?primaryAction('#guidance','Open Memory Handbook'):primaryButton('Choose a challenge','focus-challenges'))}
  ${done?completedFirstSuccess():firstSuccessJourney()}${nextLinks}`;
}
function firstSuccessJourney(){
  if(challengeState.step==='choose') return `<section class="journey-panel" id="first-success"><p class="eyebrow">First success</p><h2>Pick something useful to memorise</h2><p class="measure">No sign-in. No judgement. You will first try from memory, then learn the method and see what improves.</p><div class="challenge-grid">${beginnerChallenges.map(c=>`<button class="challenge-card" data-challenge="${c.id}"><small>${escapeHTML(c.tag||'Beginner')}</small><strong>${escapeHTML(c.title)}</strong><span>${c.time} · ${escapeHTML(c.method)}</span></button>`).join('')}</div></section>`;
  const c=challengeState.challenge;
  if(challengeState.step==='baseline') return recallStep('Baseline attempt', 'Look once, then hide the source and recall what you can. This is not a test of you; it only shows the starting point.', c, 'Save baseline', 'baseline');
  if(challengeState.step==='teach') return teachStep(c);
  if(challengeState.step==='practice') return `<section class="journey-panel"><p class="eyebrow">Practice</p><h2>Walk the story aloud or in your head</h2><div class="practice-strip">${c.material.map((x,i)=>`<span>${i+1}. ${escapeHTML(x)}</span>`).join('')}</div><p class="measure">Now close the source. Picture the first image causing the second, then the second causing the third. If an image is weak, make it larger, louder or stranger.</p><button data-journey="final">Hide source and retest</button></section>`;
  if(challengeState.step==='final') return recallStep('Retrieval test', 'The source is hidden. Recall the items in order using your image story.', c, 'Show my result', 'final');
  return successStep();
}
function teachStep(c){const pairs=c.material.slice(0,-1).map((item,i)=>`<li class="association-card"><strong>${escapeHTML(item)} → ${escapeHTML(c.material[i+1])}</strong><span>Make the first image do something impossible to the next. Add movement, sound or emotion.</span></li>`).join('');return `<section class="journey-panel"><p class="eyebrow">Learn by doing</p><h2>Build one vivid link at a time</h2><p class="measure">You are not memorising words by force. You are creating a small mental film that gives each item a route to the next.</p><ol class="method-steps"><li><strong>Concrete image:</strong> turn each item into something you can see.</li><li><strong>Exaggerate:</strong> make it too big, noisy, moving or emotional.</li><li><strong>Link:</strong> make each image interact with the next image.</li><li><strong>Retrieve:</strong> close the list and walk the story from the first image.</li></ol><div class="example-story"><p>${escapeHTML(c.prompt)}</p></div><ol class="association-list">${pairs}</ol><button data-journey="practice">Practise the associations</button></section>`}
function recallInputs(c){return `<fieldset class="recall-grid"><legend>Recall what you can. Guessing is fine; leave blanks if needed.</legend>${c.material.map((_,i)=>`<label><span>${i+1}</span><input autocomplete="off" data-recall-item aria-label="Recalled item ${i+1}"></label>`).join('')}</fieldset>`}
function recallStep(kicker, intro, c, button, mode){const isFinal=mode==='final';const source=isFinal?'<p class="source-hidden-note"><strong>Source hidden.</strong> Use the image story you practised; do not reopen the list.</p>':`<div class="study-panel"><p><strong>Look once.</strong> Do not try to be perfect. This creates your before score so you can see the method working.</p><ol class="source-list">${c.material.map(x=>`<li>${escapeHTML(x)}</li>`).join('')}</ol></div><button data-hide-source>Hide list and try from memory</button>`;return `<section class="journey-panel"><p class="eyebrow">${kicker}</p><h2>${escapeHTML(c.title)}</h2><p class="measure">${intro} Spelling does not need to be perfect.</p>${source}<form class="recall-form" data-recall="${mode}" ${isFinal?'':'hidden'}>${recallInputs(c)}<button>${button}</button></form></section>`}
function successStep(){const c=challengeState.challenge,b=challengeState.baseline||{accuracy:0,correct:0},f=challengeState.final||{accuracy:0,correct:0};const gained=Math.max(0,f.correct-b.correct);return `<section class="journey-panel success-panel"><p class="eyebrow">First success complete</p><h2>You improved your recall</h2><div class="score-comparison"><div><span>Before</span><strong>${b.correct}/${c.material.length}</strong></div><div><span>After the image story</span><strong>${f.correct}/${c.material.length}</strong></div></div><p class="result-number">${f.accuracy}%</p><p>${gained?`The method helped you recover ${gained} more item${gained===1?'':'s'}.`:'You completed the full remember-without-looking loop. The next review will strengthen it.'}</p><ul class="feedback-list"><li><strong>Memory method:</strong> ${escapeHTML(c.method)}</li><li><strong>Why it worked:</strong> vivid interacting images gave your brain a route back to the information.</li><li><strong>Next reminder:</strong> your brain now has a route to the memory. A quick 20-minute review helps keep that route open before it fades.</li></ul><label>What would you like to use this for first?<select id="firstProject"><option>Shopping lists</option><option>Names</option><option>Birthdays</option><option>Speech points</option><option>Vocabulary</option><option>Dates</option><option>Study material</option><option>A master passphrase practice plan, stored outside this app</option></select></label><small>Do not store real passwords here. Use a reputable password manager for passwords.</small><button data-complete-first>Save my first success</button></section>`}
function completedFirstSuccess(){const fs=get().firstSuccess;return `<section class="journey-panel success-panel"><p class="eyebrow">First success saved</p><h2>You have already proved the method works.</h2><p>Your first challenge was <strong>${escapeHTML(fs?.challengeTitle||'a beginner challenge')}</strong>. Choose a personal project next.</p><form id="projectForm"><label>My first useful memory project<select name="project"><option>Birthdays</option><option>Important telephone numbers</option><option>Shopping lists</option><option>Names</option><option>Speech points</option><option>Vocabulary</option><option>Dates</option><option>Study material</option><option>A master passphrase practice plan, stored outside this app</option></select></label><small>Do not store real passwords here. Use a reputable password manager for passwords.</small><button>Save project</button></form></section>`}

function toolCard(href,img,title,desc){return `<a class="path-card" href="${href}" aria-label="Open ${escapeHTML(title)}"><img class="tool-illustration" src="${img}" alt="" aria-hidden="true"><strong>${escapeHTML(title)}</strong><span>${escapeHTML(desc)}</span></a>`}
function library(){return `${page('Library','Choose a memory tool when you need it',`<p class="lead">Start with your real-life project. Each tool below helps with a different kind of information.</p>`,primaryAction('#palaces','Create or edit a palace'))}<section class="quiet-grid tool-grid">${toolCard('#palaces','assets/tool-palace.svg','Memory palaces',`Use familiar places to remember ordered lists, talks and study notes. ${get().palaces.length||1} route started.`)}${toolCard('#major','assets/tool-major.svg','Number images','Turn numbers into memorable pictures when numbers matter.')}${toolCard('#pao','assets/tool-pao.svg','PAO system','Advanced: combine people, actions and objects for long numbers or cards.')}${toolCard('#symbols','assets/tool-symbols.svg','Symbol bank','Reusable pictures for ideas like time, risk, money and growth.')}${toolCard('#names','assets/tool-names.svg','Name images','Create visual hooks for names, faces and vocabulary.')}${toolCard('#contract','assets/tool-contract.svg','Training contract','Keep your reason for practising visible.')}</section>`}
function recentRecallList(results){const recent=results.slice(-6).reverse();if(!recent.length)return '<div class="empty-state"><h2>No recall results yet</h2><p>Complete one recall test and your first result will appear here.</p></div>';return `<ol class="recall-list" aria-label="Recent recall results">${recent.map(r=>`<li><div class="recall-row"><strong>${escapeHTML(r.day?`Day ${r.day}`:'First success')}</strong><span>${r.accuracy}%</span></div><div class="recall-meter" aria-hidden="true"><span style="width:${Math.max(2,Math.min(100,r.accuracy))}%"></span></div><small>${escapeHTML(r.type||'Recall practice')} · ${escapeHTML(r.technique||'memory technique')}</small></li>`).join('')}</ol>`}
function progress(){const r=get().results;return `${page('Progress','What is improving?',`<p class="lead">Analytics are here when you need them, away from the main learning task.</p>`,primaryAction('#reviews','Review due material'))}<div class="grid"><div class="card metric"><span>Immediate</span><strong>${mean(r.map(x=>x.accuracy))}%</strong></div><div class="card metric"><span>Delayed</span><strong>${mean(get().reviews.filter(x=>x.reviewScore!=null).map(x=>x.reviewScore))}%</strong></div><div class="card metric"><span>Completed sessions</span><strong>${r.length}</strong></div></div><section class="card"><div class="section-heading"><h2>Recent recall</h2><p class="muted">Latest retrieval scores, shown as simple progress bars.</p></div>${recentRecallList(r)}<p>${insight()}</p></section><section class="quiet-grid"><a class="path-card" href="#belts"><strong>Belts and examinations</strong><span>Progression when ready</span></a><a class="path-card" href="#reviews"><strong>Review queue</strong><span>${due().length} due now</span></a></section>`}
function displayReviewItem(x){const text=String(x||'');return text===text.toLowerCase()&&text.length<28?text.charAt(0).toUpperCase()+text.slice(1):text}
const illustrationTypes={'front gate':'gate','path':'path','front door':'door','doormat':'mat','hall table':'table','mirror':'mirror','stairs':'stairs','living-room door':'door','living room door':'door','sofa':'sofa','fireplace':'fireplace',sauce:'sauce',seed:'seed',sun:'sun',sum:'sum',syrup:'sauce',seal:'seal',sage:'leaf',sock:'sock',safe:'safe',soap:'soap',toes:'foot',tot:'toy',tin:'tin',tomb:'tomb',tire:'tire',towel:'towel',dish:'dish',tack:'tack',dove:'dove',tub:'tub'};
function illustrationType(label){return illustrationTypes[String(label||'').toLowerCase().trim()]||'object'}
function iconPaths(type){const paths={gate:'<path d="M28 82V52c0-20 48-20 48 0v30"/><path d="M40 82V56c0-9 24-9 24 0v26"/><path d="M24 82h56"/>',path:'<path d="M18 84c20-24 18-48 44-60"/><path d="M46 88c10-26 14-42 38-56"/>',door:'<rect x="32" y="22" width="38" height="62" rx="4"/><circle cx="62" cy="54" r="3"/>',mat:'<rect x="22" y="54" width="58" height="24" rx="5"/><path d="M32 64h38"/>',table:'<path d="M22 46h58"/><path d="M32 46v34M70 46v34"/><path d="M36 34h28"/>',mirror:'<ellipse cx="52" cy="50" rx="24" ry="31"/><path d="M40 38c8-7 18-7 26 0"/>',stairs:'<path d="M20 78h18V62h18V46h18V30h12"/>',sofa:'<path d="M24 58h56v22H24z"/><path d="M28 46h48v18"/><path d="M30 80v8M74 80v8"/>',fireplace:'<rect x="24" y="32" width="56" height="52" rx="6"/><path d="M42 84c-6-16 14-20 10-36 16 12 20 24 10 36"/>',sauce:'<path d="M44 18h18l4 18v44c0 8-26 8-26 0V36z"/><path d="M41 48h24"/>',seed:'<path d="M52 76c-20-16-14-44 16-50 8 26-2 44-16 50z"/><path d="M50 78c-2-18 8-34 20-48"/>',sun:'<circle cx="52" cy="52" r="18"/><path d="M52 18v12M52 74v12M18 52h12M74 52h12M28 28l9 9M67 67l9 9M76 28l-9 9M37 67l-9 9"/>',sum:'<path d="M70 28H34l22 24-22 24h36"/>',seal:'<path d="M24 68c16-26 48-30 62-4-18 10-44 16-62 4z"/><circle cx="64" cy="56" r="3"/>',leaf:'<path d="M28 70c8-34 36-44 56-42-2 30-24 50-56 42z"/><path d="M30 70c16-16 30-27 52-40"/>',sock:'<path d="M38 22h24v36c12 0 20 8 18 18-2 13-36 13-42 3z"/>',safe:'<rect x="24" y="30" width="58" height="48" rx="7"/><circle cx="52" cy="54" r="10"/><path d="M52 44v20M42 54h20"/>',soap:'<rect x="24" y="44" width="58" height="30" rx="15"/><circle cx="70" cy="32" r="6"/><circle cx="80" cy="22" r="4"/>',foot:'<path d="M32 74c8-30 30-28 36-8 3 10-2 18-14 18H34z"/><circle cx="68" cy="38" r="4"/><circle cx="58" cy="32" r="4"/><circle cx="48" cy="31" r="4"/>',toy:'<circle cx="52" cy="52" r="22"/><path d="M38 38l28 28M66 38L38 66"/>',tin:'<ellipse cx="52" cy="32" rx="24" ry="8"/><path d="M28 32v42c0 10 48 10 48 0V32"/><ellipse cx="52" cy="74" rx="24" ry="8"/>',tomb:'<path d="M30 84V42c0-24 44-24 44 0v42z"/><path d="M42 54h20M52 44v30"/>',tire:'<circle cx="52" cy="52" r="30"/><circle cx="52" cy="52" r="14"/>',towel:'<path d="M30 24h46v62H30z"/><path d="M40 24v62M30 40h46"/>',dish:'<ellipse cx="52" cy="60" rx="32" ry="16"/><ellipse cx="52" cy="58" rx="18" ry="7"/>',tack:'<path d="M36 26h32l-8 28 16 12H28l16-12z"/><path d="M52 66v24"/>',dove:'<path d="M24 58c22-24 42-24 60 0-18 0-24 14-40 18-8 2-16-4-20-18z"/><path d="M60 48l24-14-10 22"/>',tub:'<path d="M22 48h62v18c0 14-10 22-24 22H46c-14 0-24-8-24-22z"/><path d="M68 48V32c0-8 10-8 10 0"/>',object:'<rect x="28" y="28" width="50" height="50" rx="14"/><path d="M38 58c8-12 18-12 30 0"/>'};return paths[type]||paths.object}
function memoryThumb(label,kind='item'){const type=illustrationType(label);return `<svg class="memory-thumb ${kind}" viewBox="0 0 104 104" role="img" aria-label="Illustration of ${escapeHTML(label)}"><rect width="104" height="104" rx="28" class="thumb-bg"></rect><g class="thumb-line" fill="none" stroke-linecap="round" stroke-linejoin="round" stroke-width="7">${iconPaths(type)}</g></svg>`}

function noteValue(key){return get().notes?.find(n=>n.key===key)?.text||''}
function noteEditorField(key,label,context,href=''){return `<label class="note-field">${label}<textarea data-note-key="${escapeHTML(key)}" data-note-context="${escapeHTML(context)}" data-note-href="${escapeHTML(href)}" autocomplete="off" placeholder="Note a starting image, weak link or confusion.">${escapeHTML(noteValue(key))}</textarea></label><p class="muted">Saved automatically and available from Notes.</p>`}
function saveNote(key,context,text,href=''){update(s=>{s.notes=s.notes||[];const now=Date.now(),existing=s.notes.find(n=>n.key===key);if(existing){existing.text=text;existing.context=context||existing.context;existing.href=href||existing.href;existing.updatedAt=now}else s.notes.push({key,context,text,href,createdAt:now,updatedAt:now})})}
const noteContext={key:'page:dashboard',context:'Today',href:'#dashboard'};
function setNoteContext(key='page:dashboard',context='Today',href='#dashboard'){noteContext.key=key;noteContext.context=context;noteContext.href=href;const title=$('#noteContextTitle'),link=$('#noteContextLink'),text=$('#noteText');if(title)title.textContent=context;if(link){link.href=href;link.textContent=`Open ${key}`}if(text&&document.activeElement!==text)text.value=noteValue(key)}
function toggleNoteDrawer(open){const drawer=$('#noteDrawer');if(!drawer)return;const next=open??!drawer.classList.contains('open');drawer.classList.toggle('open',next);drawer.setAttribute('aria-expanded',String(next));$$('[aria-controls="noteDrawer"]').forEach(control=>control.setAttribute('aria-expanded',String(next)));if(next)$('#noteText')?.focus()}
function bindNoteDrawer(){const text=$('#noteText');$$('[aria-controls="noteDrawer"]').forEach(control=>{if(!control.dataset.bound){control.dataset.bound='1';control.addEventListener('click',()=>toggleNoteDrawer())}});if(text&&!text.dataset.bound){text.dataset.bound='1';text.addEventListener('input',()=>saveNote(noteContext.key,noteContext.context,text.value,noteContext.href))}window.addEventListener('dojo:note-context',e=>setNoteContext(e.detail?.key,e.detail?.context,e.detail?.href))}
function routeNoteContext(hash){const labels={dashboard:'Today',learn:'Learn',library:'Library',progress:'Progress',train:'Training',reviews:'Reviews',notes:'Notes',settings:'Settings',design:'Design studio'};setNoteContext(`page:${hash}`,labels[hash]||hash||'Today',`#${hash||'dashboard'}`)}
function reviewSummary(r){const count=r.material?.length||0, day=r.sessionDay?`Day ${r.sessionDay}`:'First success', type=r.materialType||r.type||'words from your first image story';return `${day}: remember ${count} ${type}${r.technique?` with ${r.technique}`:''}`}
function reviewCue(r,index,total){const created=r.createdAt?`Saved ${formatDate(r.createdAt)}`:'Saved review';const position=total>1?`Review ${index+1} of ${total} · `:'';return `${position}${created}. Recall the list you learned under “${reviewSummary(r)}”.`}
function reviewView(){const items=uniqueReviews(get().reviews.filter(r=>r.status==='active'));return page('Reviews','Retrieve before you reread',`<p class="lead">Write what you remember first. The source stays hidden until you check your recall.</p>`,items.length?primaryAction('#reviews','Start with the first due review'):'') + (items.length?items.map((r,index)=>`<article class="card" id="review-${escapeHTML(r.id)}" data-review-card="${escapeHTML(r.id)}" data-note-key="review:${escapeHTML(r.id)}" data-note-context="Retrieval · ${escapeHTML(reviewSummary(r))}"><h3>${escapeHTML(reviewSummary(r))}</h3><p>${r.nextReviewAt<=Date.now()?'<strong class="success">Due now</strong>':`Due ${formatDate(r.nextReviewAt)}`} · strength: ${r.strength}</p><p class="muted review-cue">${escapeHTML(reviewCue(r,index,items.length))}</p><details><summary>Start recall</summary><p>Type the items from memory, one per line. Then check your recall and reveal the source.</p><form class="review-form" data-review-form="${r.id}"><label>Your remembered items<textarea data-review-answer="${r.id}" autocomplete="off" placeholder="One item per line"></textarea></label><p class="muted">Use the Notes tab to record what made this retrieval hard.</p><button>Check recall</button></form><div id="review-result-${r.id}"></div></details><div class="actions"><button class="secondary" data-review="snooze:${r.id}">Snooze 1 day</button><button class="secondary" data-review="retire:${r.id}">Retire</button><button class="secondary" data-review="restart:${r.id}">Restart</button></div></article>`).join(''):'<div class="empty-state"><h2>No reviews due</h2><p>Complete a training session or first-success challenge to schedule future retrieval.</p><a class="button" href="#learn">Learn something useful</a></div>')}

function strongWeak(best){const by={};get().results.forEach(r=>(by[r.technique]??=[]).push(r.accuracy));const a=Object.entries(by).map(([k,v])=>[k,mean(v)]).sort((a,b)=>b[1]-a[1]);return a.length?(best?a[0]:a.at(-1))[0]:'Complete a session to discover this'}
function insight(){const s=get(),a=mean(s.results.map(x=>x.accuracy)),d=mean(s.reviews.filter(x=>x.reviewScore!=null).map(x=>x.reviewScore));if(!s.results.length)return 'Your first scored retrieval will establish a baseline.';if(d&&a-d>15)return 'Your images are memorable immediately but weaken during delayed recall.';if(s.results.reduce((n,x)=>n+x.orderErrors,0)>s.results.reduce((n,x)=>n+x.omitted,0))return 'Order errors are more common than omissions. Strengthen your route.';return 'Keep prioritising accurate recall and practical use over streaks.'}
function palaces(){return page('Library','Memory palaces',`<p class="lead">A good locus is fixed, distinct, easy to visualise, naturally ordered and large enough for an exaggerated image.</p>`,primaryAction('#library','Back to Library'))+`<button id="addPalace">Add palace</button>${get().palaces.map((p,pi)=>`<article class="card"><h2>${escapeHTML(p.name)}</h2><p>${escapeHTML(p.routeDescription||'')}</p><div class="route">${p.locations.map((l,i)=>`<div class="locus">${memoryThumb(l.name,'palace-thumb')}<input aria-label="Location ${i+1}" value="${escapeHTML(l.name)}" data-locus="${pi}:${i}"><button class="secondary" data-del-locus="${pi}:${i}" aria-label="Delete location">×</button></div>`).join('')}</div><div class="actions"><button data-add-locus="${pi}">Add location</button><button class="secondary" data-reverse="${pi}">Practise backwards</button><button class="secondary" data-duplicate="${pi}">Duplicate</button><button class="secondary" data-export-palace="${pi}">Export</button></div></article>`).join('')}`}
function sceneByNumber(number){return data['major-system-scenes']?.entries?.find(x=>x.number===number)}
function sceneStatus(scene){return scene?.generationReviewStatus==='pending'?'Scene pending review':'Reference scene ready'}
function majorSceneFigure(scene, peg){if(scene?.imageAssetPath)return `<figure class="major-scene-figure"><img src="${escapeHTML(scene.imageAssetPath)}" alt="Mnemonic scene for ${escapeHTML(peg)}" loading="lazy"><figcaption>${escapeHTML(scene.shortSpokenMnemonic||`Picture ${peg} moving dramatically.`)}</figcaption></figure>`;return `<div class="missing-asset" role="note"><strong>Scene pending.</strong><span>No reviewed illustration yet. Use your own image for now.</span></div>`}
function soundControls(scene){const disabled=!scene?.audioAssetPath?'disabled':'';return `<div class="audio-controls" aria-label="Scene audio controls"><button class="secondary" data-speak-peg="${escapeHTML(scene?.pegWord||'')}" type="button">Say peg</button><button class="secondary" data-narrate="${escapeHTML(scene?.number||'')}" type="button">Narrate scene</button><button class="secondary" data-sfx="${escapeHTML(scene?.number||'')}" type="button" ${disabled}>Sound effects</button></div>`}
function sensoryCues(scene){if(!scene||scene.generationReviewStatus==='pending')return '<p class="muted">Sensory scene cues are pending for this number.</p>';return `<ul class="sensory-cues"><li><strong>Hear:</strong> ${escapeHTML(scene.imaginedSound)}</li><li><strong>Imagine the touch:</strong> ${escapeHTML(scene.imaginedTouch)}</li><li><strong>Imagine the smell:</strong> ${escapeHTML(scene.imaginedSmell)}</li>${scene.imaginedTaste?`<li><strong>Imagine the taste:</strong> ${escapeHTML(scene.imaginedTaste)}</li>`:''}<li><strong>Emotion:</strong> ${escapeHTML(scene.emotion)}</li></ul>`}
function major(){const scenes=data['major-system-scenes']?.entries||[];const approved=scenes.filter(x=>x.generationReviewStatus!=='pending').length;return page('Library','Major System 00–99',`<p class="lead">Learn numbers by recalling the sounds and peg first, then reveal a vivid scene. The first ten scenes are a reviewed reference batch; later numbers are deliberately pending until individually designed.</p>`,primaryAction('#library','Back to Library'))+`<section class="card"><h2>How to use a card</h2><ol class="method-steps"><li>Look at the number.</li><li>Recall the consonant sounds and peg word before revealing.</li><li>Reveal the scene, then imagine the sound, touch and smell.</li><li>Replace the peg or scene if your own image is stronger.</li></ol><p class="muted">Reference scenes ready: ${approved}/100. Pending scenes are shown clearly rather than filled with duplicate placeholders.</p><div class="actions"><button id="majorTest">Forward recall</button><button class="secondary" id="majorReverseTest">Reverse recall</button><button class="secondary" id="majorCsv">Export CSV</button><a class="button secondary" href="#major-scenes-review">Review 00–09 scene specs</a></div></section><div class="major-grid">${get().majorSystem.map((x,i)=>{const peg=x.userImage||x.defaultImage,scene=sceneByNumber(x.number);return `<article class="major-cell" data-major-card="${escapeHTML(x.number)}"><div class="major-number-row"><strong>${x.number}</strong><span class="status-pill">${escapeHTML(sceneStatus(scene))}</span></div><p class="muted">Recall sounds and peg before opening.</p><details><summary>Reveal peg and scene</summary><p><strong>Sounds:</strong> ${escapeHTML(x.sounds)}</p><label>Personal peg<input aria-label="Image for ${x.number}" value="${escapeHTML(peg)}" data-major="${i}"></label>${majorSceneFigure(scene,peg)}${soundControls(scene)}${sensoryCues(scene)}<label>Personal scene note<textarea data-scene-note="${i}" aria-label="Personal scene for ${x.number}">${escapeHTML(x.sceneNote||'')}</textarea></label></details></article>`}).join('')}</div>`}
function majorScenesReview(){const entries=data['major-system-scenes']?.entries||[];const review=entries.slice(0,10);const warnings=[];for(const field of ['dramaticAction','unusualLocation','dominantColourPalette']){const seen=new Map();review.forEach(e=>{const v=(e[field]||'').toLowerCase();if(!v)warnings.push(`${e.number}: missing ${field}`);else if(seen.has(v))warnings.push(`${e.number}: duplicate ${field} with ${seen.get(v)}`);else seen.set(v,e.number)})}review.forEach(e=>['subject','emotion','imaginedSound','imaginedTouch','imaginedSmell','fullImageGenerationPrompt','imageAssetPath'].forEach(f=>{if(!e[f])warnings.push(`${e.number}: missing ${f}`)}));return page('Library','Major scene review 00–09',`<p class="lead">Development review for the reference batch. Each prompt must be active, sensory, concrete and visually distinct.</p>`,primaryAction('#major','Back to Major System'))+`<section class="card validation-panel"><h2>Validation warnings</h2>${warnings.length?`<ul>${warnings.map(w=>`<li>${escapeHTML(w)}</li>`).join('')}</ul>`:'<p>No visible warnings for 00–09.</p>'}</section><div class="scene-review-grid">${review.map(e=>`<article class="card scene-spec"><div class="major-number-row"><h2>${e.number} · ${escapeHTML(e.pegWord)}</h2><span class="status-pill">${escapeHTML(e.generationReviewStatus)}</span></div>${majorSceneFigure(e,e.pegWord)}<dl class="scene-dl"><dt>Sounds</dt><dd>${escapeHTML(e.sounds)}</dd><dt>Subject</dt><dd>${escapeHTML(e.subject)}</dd><dt>Action</dt><dd>${escapeHTML(e.dramaticAction)}</dd><dt>Location</dt><dd>${escapeHTML(e.unusualLocation)}</dd><dt>Feature</dt><dd>${escapeHTML(e.exaggeratedVisualFeature)}</dd><dt>Emotion</dt><dd>${escapeHTML(e.emotion)}</dd><dt>Sound</dt><dd>${escapeHTML(e.imaginedSound)}</dd><dt>Touch</dt><dd>${escapeHTML(e.imaginedTouch)}</dd><dt>Smell</dt><dd>${escapeHTML(e.imaginedSmell)}</dd>${e.imaginedTaste?`<dt>Taste</dt><dd>${escapeHTML(e.imaginedTaste)}</dd>`:''}<dt>Palette</dt><dd>${escapeHTML(e.dominantColourPalette)}</dd><dt>Prompt</dt><dd><pre><code>${escapeHTML(e.fullImageGenerationPrompt)}</code></pre></dd></dl></article>`).join('')}</div>`}
function genericBuilder(type,title,fields,guidance=''){const items=get()[type];return page('Library',title,`<p class="lead">${guidance||'Build a personal memory library gradually as real needs appear.'}</p>`,primaryAction('#library','Back to Library'))+`<form id="genericForm" data-type="${type}" class="card">${fields.map(f=>`<label>${f}<input name="${f}" required></label>`).join('')}<button>Add entry</button></form><div class="quiet-grid">${items.map((x,i)=>`<article class="card"><h3>${escapeHTML(x[fields[0]]||x.concept||'Entry')}</h3>${fields.slice(1).map(f=>`<p><strong>${f}:</strong> ${escapeHTML(x[f]||'—')}</p>`).join('')}<button class="danger" data-delete-generic="${type}:${i}">Delete</button></article>`).join('')||'<div class="empty-state"><h2>No entries yet</h2><p>Add one useful item when you need it.</p></div>'}</div>`}
function belts(){const completed=get().results.length;return page('Progress','Belts and examinations',`<p class="lead">Use exams after you have experienced real recall improvement.</p>`,primaryAction('#progress','Back to Progress'))+data.belts.map((b,i)=>`<article class="card belt" style="--belt:${b.color}"><p class="eyebrow">${b.badge}</p><h2>${b.name}: ${b.subtitle}</h2><p>${b.purpose}</p><details><summary>Examination and eligibility</summary><p>${b.exam.brief}</p><ul>${b.exam.checklist.map(x=>`<li>${x}</li>`).join('')}</ul><p><strong>Unlock:</strong> ${b.unlock}</p><button data-exam="${b.id}" ${completed<(i+1)*3?'disabled':''}>Take eligibility check</button></details></article>`).join('')}
function guidance(){return page('Handbook','Memory Handbook',`<p class="lead">Theory lives here, after practice. Each chapter explains what to use, when not to use it, mistakes and a short exercise.</p>`,primaryAction('#learn','Back to Learn'))+`<div class="handbook-grid">${handbookChapters.map(ch=>`<article class="card handbook-card">${memoryThumb(ch,'handbook-thumb')}<h2>${escapeHTML(ch)}</h2><p><strong>What it is:</strong> A practical way to make information more noticeable, structured and retrievable.</p><p><strong>Good for:</strong> Useful facts, sequences, names, numbers or study material when accuracy matters.</p><p><strong>When not to use it:</strong> Safety-critical data or real passwords that belong in secure systems.</p><ol><li>Notice the exact information.</li><li>Make a concrete image or structure.</li><li>Force interaction, movement or location.</li><li>Retrieve without looking.</li><li>Repair weak points.</li></ol><p><strong>Practice:</strong> Try one tiny example, then open a guided challenge.</p><a href="#learn">Guided challenge</a></article>`).join('')}</div>`}

function notesPage(){const notes=(get().notes||[]).slice().sort((a,b)=>(b.updatedAt||0)-(a.updatedAt||0));return page('Notes','Retrieval notes',`<p class="lead">Review and edit the memory issues you noticed during warm-ups and recall tests.</p>`,primaryAction('#settings','Back to settings'))+(notes.length?`<div class="quiet-grid">${notes.map(n=>`<article class="card"><h2>${escapeHTML(n.context||'Retrieval note')}</h2><p class="muted">Reference: ${escapeHTML(n.key)}</p>${n.href?`<a class="button secondary" href="${escapeHTML(n.href)}">Open linked area</a>`:''}${noteEditorField(n.key,'Note',n.context||'Retrieval note',n.href||'')}</article>`).join('')}</div>`:'<div class="empty-state"><h2>No notes yet</h2><p>Open the floating Notes tab while training or reviewing to capture what was hard to remember.</p><a class="button" href="#train">Open training</a></div>')}
function contract(){const c=get().contract,fs=['Why I want a trained memory','What I want to remember','Daily minimum','Normal training time','Training location','What I will do after missing a day','My first mastery project','Start date','Signature or name'];return page('Profile','Personal training contract',`<p class="lead">Identity before streaks: I am training the skill of remembering.</p>`,primaryAction('#settings','Back to settings'))+`<form id="contractForm" class="card">${fs.map(f=>`<label>${f}<input name="${f}" value="${escapeHTML(c[f]||'')}"></label>`).join('')}<button>Save contract</button></form>`}
function poster(){return `<article class="poster"><p class="eyebrow">Memory Mastery</p><h1>Daily Memory Warm-up</h1><h2>Recall before review</h2><ol><li>Close yesterday’s material.</li><li>Walk through yesterday’s palace.</li><li>Retrieve each image.</li><li>Mark it clear, vague or missing.</li><li>Repair only weak memories.</li><li>Then begin today’s training.</li></ol><h2>Why?</h2><ul><li>Retrieval strengthens the route back to a memory.</li><li>Effortful recall is more valuable than rereading.</li><li>Errors show which images need improvement.</li><li>Daily retrieval prevents rapid forgetting.</li></ul><blockquote>Notice. Encode. Place. Retrieve. Review.</blockquote><div class="actions no-print"><button onclick="print()">Print A4 poster</button></div></article>`}
function settings(){const p=get().profile,owner=signedInEmail.toLowerCase()===ARCHIVE_OWNER_EMAIL;return page('Profile','Settings and data',`<p class="lead">Account, appearance, export and portability live here so learning screens can stay focused.</p>`,primaryAction('#dashboard','Back to Today'))+`<div class="card"><h2>Appearance</h2><label>Colour theme<select id="colorTheme"><option value="pastelPaper" ${p.colorTheme==='pastelPaper'?'selected':''}>Pastel paper</option><option value="pastelMint" ${p.colorTheme==='pastelMint'?'selected':''}>Pastel mint</option><option value="pastelLavender" ${p.colorTheme==='pastelLavender'?'selected':''}>Pastel lavender</option><option value="pastelSunset" ${p.colorTheme==='pastelSunset'?'selected':''}>Pastel sunset</option><option value="mono" ${p.colorTheme==='mono'?'selected':''}>High-contrast mono</option></select></label><label>Layout and look<select id="uiStyle"><option value="smartpaper" ${p.uiStyle==='smartpaper'?'selected':''}>Calm learning app</option><option value="focus" ${p.uiStyle==='focus'?'selected':''}>Focus mode</option><option value="compact" ${p.uiStyle==='compact'?'selected':''}>Compact</option><option value="minimal" ${p.uiStyle==='minimal'?'selected':''}>Minimal notebook</option></select></label><button id="themeSetting">Toggle light / dark</button></div><div class="card"><h2>Backup and portability</h2><p>Guest data stays in this browser. Export it before clearing site data or moving devices.</p><div class="actions"><button id="exportJson">Export JSON backup</button><button id="resultsCsv">Results CSV</button><button onclick="print()">Print progress</button><label class="button">Import JSON<input id="importJson" type="file" accept="application/json" hidden></label></div><button class="danger" id="reset">Erase local data</button></div><div class="card" id="authPanel"><h2>Firebase sync</h2><p>${configured()?'Firebase configuration detected. Sign in with Google or phone to combine this browser’s guest progress with your cloud backup.':'Guest mode is active. Add your public Firebase configuration in <code>js/firebase.js</code>.'}</p><p class="muted">Guest progress is stored only in this browser. Private browsing, another device, or an older app version can appear empty until you sign in and the device/cloud backup is combined.</p><p class="muted"><strong>Phone sign-in:</strong> SMS sign-in also requires the developer to enable the relevant Firebase SMS region policy. If you see a region error, use Google sign-in and ask the developer to enable your country/region in Firebase Authentication.</p><div class="auth-options"><button id="googleSignIn" type="button">Continue with Google</button><form id="phoneAuthForm" class="auth-form"><label for="phoneNumber">Phone number<input id="phoneNumber" name="phoneNumber" type="tel" inputmode="tel" autocomplete="tel" placeholder="+44 7123 456789" required></label><button type="submit">Text me a code</button></form><form id="phoneCodeForm" class="auth-form" hidden><label for="phoneCode">Verification code<input id="phoneCode" name="phoneCode" inputmode="numeric" autocomplete="one-time-code" required></label><button type="submit">Verify and sync</button></form><div id="phoneRecaptcha"></div></div></div><div class="quiet-grid"><a class="path-card" href="#contract"><strong>Training contract</strong><span>Edit your purpose</span></a><a class="path-card" href="#poster"><strong>Warm-up poster</strong><span>Print or display</span></a><a class="path-card" href="#versions"><strong>Version archive</strong><span>Trace important changes</span></a><a class="path-card" href="#notes"><strong>Retrieval notes</strong><span>Review weak starts and recall issues</span></a>${owner?'<a class="path-card" href="#design"><strong>Design studio</strong><span>Tune the interface visually</span></a>':''}</div>`}

function designStudio(){const owner=signedInEmail.toLowerCase()===ARCHIVE_OWNER_EMAIL;if(!owner)return page('Owner tool','Design studio',`<p class="lead">This visual-tuning tool is reserved for the archive owner and stays outside learner onboarding and practice.</p>`,primaryAction('#settings','Back to settings'));return page('Owner tool','Design studio',`<p class="lead">Select interface elements to tune their visual presentation without placing developer controls in beginner learning flows.</p><p class="measure">Use this workspace for deliberate visual adjustments, then check the affected learning screens at every supported width.</p>`,primaryButton('Start selecting elements','start-design-selection'))}


function versions(){const archive=data['version-archive'];const owner=signedInEmail.toLowerCase()===ARCHIVE_OWNER_EMAIL;return page('Profile','Version archive',`<p class="lead">Browse the version history from the footer. Full archived build snapshots remain gated to the archive owner; public cards still open their referenced commit.</p>`,primaryAction('#settings','Back to settings'))+`<section class="card"><h2>Archive policy</h2><p>${escapeHTML(archive.purpose)}</p><p class="muted">${escapeHTML(archive.rebuildPolicy.whyNotBundleEveryBuild)}</p>${owner?'':'<p class="muted">Sign in with the archive owner account to open full historical snapshots and latest-data rebuilds.</p>'}</section><div class="quiet-grid">${archive.versions.map(v=>`<article class="card linked-card" data-card-href="https://github.com/nirav2000/MemoryMastery/commit/${escapeHTML(v.commit)}" tabindex="0" role="link" aria-label="View commit ${escapeHTML(v.commit)} for ${escapeHTML(v.label)}">${v.screenshot?`<img class="archive-thumb" src="${escapeHTML(v.screenshot)}" alt="First screen of ${escapeHTML(v.label)}" loading="lazy">`:''}<p class="eyebrow">${escapeHTML(v.status)} · ${escapeHTML(v.date)}</p><h2>${escapeHTML(v.label)}</h2><p>${escapeHTML(v.summary)}</p><ul>${v.keyChanges.map(x=>`<li>${escapeHTML(x)}</li>`).join('')}</ul><div class="actions">${owner&&v.archivePath?`<a class="button" href="${escapeHTML(v.archivePath)}">Open archived build</a><a class="button secondary" href="${escapeHTML(v.latestDataPath)}">Try latest data</a>`:''}<a class="button secondary" href="https://github.com/nirav2000/MemoryMastery/commit/${escapeHTML(v.commit)}" target="_blank" rel="noreferrer">View commit ${escapeHTML(v.commit)}</a></div>${v.compatibilityNote?`<small>${escapeHTML(v.compatibilityNote)}</small>`:''}</article>`).join('')}</div><section class="card"><h2>Rebuild an old version</h2><p>Use git history for exact reconstruction rather than placing many obsolete copies in the live app.</p><pre><code>${archive.rebuildPolicy.commands.map(escapeHTML).join('\n')}</code></pre></section>`}


function legalPage(kind){const pages={terms:['Terms','Use Memory Mastery for learning and practice. Keep personal, legal or safety-critical records in the appropriate secure place.'],privacy:['GDPR & privacy','Guest data is stored in this browser. If you sign in, your app backup is stored in Firebase under your authenticated user ID. Export or erase local data from Settings.'],cookies:['Cookie policy','Memory Mastery does not need advertising cookies. The app uses browser storage for progress and Firebase authentication may use provider/session storage when you sign in.']};const [title,copy]=pages[kind]||pages.terms;return page('Legal',title,`<div class="legal-copy"><p>${escapeHTML(copy)}</p><p>These short notices are simple product information and should be reviewed before public commercial use.</p></div>`,primaryAction('#settings','Back to settings'))}


function cardDestination(card){
  if(card.dataset.cardHref) return card.dataset.cardHref;
  if(card.querySelector('button,input,select,textarea,summary,details')) return '';
  const links=$$('a[href]',card);
  return links.length===1?links[0].getAttribute('href'):'';
}
function bindLinkedCards(){
  $$('.linked-card[data-card-href], .card, .handbook-card').forEach(card=>{
    const href=cardDestination(card);
    if(!href||card.dataset.cardBound)return;
    card.dataset.cardBound='1';
    if(!card.hasAttribute('tabindex')) card.tabIndex=0;
    if(!card.hasAttribute('role')) card.setAttribute('role','link');
    card.classList.add('clickable-card');
    const go=()=>{location.href=href};
    card.addEventListener('click',e=>{if(e.target.closest('a,button,input,select,textarea,summary,details'))return;go()});
    card.addEventListener('keydown',e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();go()}});
  });
}

function route(){const hash=location.hash.slice(1)||'dashboard';const views={dashboard,learn,library,progress,train:()=>trainingView(data.curriculum),reviews:reviewView,palaces,major,pao:()=>genericBuilder('pao','Person–Action–Object',['Number or card','Person','Action','Object','Visual description','Familiarity','Distinctiveness'],'Choose instantly recognisable people, distinctive actions and concrete objects. Avoid duplicates.'),symbols:()=>genericBuilder('symbols','Symbol bank',['concept','image','meaning','exampleUse','category','strength']),names:()=>genericBuilder('nameImages','Name image builder',['Name','Sound-alike image','Meaning or origin','Distinctive image','Example association','Notes']),belts,guidance,notes:notesPage,contract,poster,settings,versions,design: designStudio,'major-scenes-review':majorScenesReview,terms:()=>legalPage('terms'),privacy:()=>legalPage('privacy'),cookies:()=>legalPage('cookies')};$('#main').innerHTML=(views[hash]||dashboard)();$$('nav a').forEach(a=>{const active=a.hash===`#${hash}`;a.classList.toggle('active',active);active?a.setAttribute('aria-current','page'):a.removeAttribute('aria-current')});routeNoteContext(hash);bind(hash);bindLinkedCards();badges();scrollTo(0,0)}
function bind(hash){
  if(hash==='train') bindTraining();
  $$('[data-note-key]').forEach(el=>el.addEventListener('input',()=>saveNote(el.dataset.noteKey,el.dataset.noteContext,el.value,el.dataset.noteHref||'')));
  $$('[data-review-card]').forEach(card=>{const activate=()=>setNoteContext(card.dataset.noteKey,card.dataset.noteContext,'#reviews');card.addEventListener('focusin',activate);card.addEventListener('click',activate);$('details',card)?.addEventListener('toggle',e=>{if(e.target.open)activate()})});
  $$('[data-challenge]').forEach(b=>b.onclick=()=>{challengeState.challenge=beginnerChallenges.find(c=>c.id===b.dataset.challenge);challengeState.step='baseline';route()});
  $$('[data-hide-source]').forEach(b=>b.onclick=()=>{const source=b.previousElementSibling;source.hidden=true;const form=$('.recall-form',b.parentElement);if(form)form.hidden=false;b.remove();const firstInput=$('[data-recall-item]',b.parentElement);if(firstInput)firstInput.focus()});
  $('[data-action="focus-challenges"]')?.addEventListener('click',()=>{$('#first-success')?.scrollIntoView({behavior:'smooth',block:'start'});$('.challenge-card')?.focus()});
  $$('[data-journey]').forEach(b=>b.onclick=()=>{challengeState.step=b.dataset.journey;route()});
  $$('.recall-form').forEach(f=>f.onsubmit=e=>{e.preventDefault();const mode=f.dataset.recall,score=scoreOrderedRecall(challengeState.challenge.material,$$('[data-recall-item]',f).map(i=>i.value).join('\n'));challengeState[mode]=score;challengeState.step=mode==='baseline'?'teach':'success';route()});
  $('[data-complete-first]')?.addEventListener('click',()=>{const c=challengeState.challenge, result={day:0,date:Date.now(),belt:'white',type:'beginner challenge',technique:c.method,...challengeState.final};update(s=>{s.firstSuccess={completed:true,challengeId:c.id,challengeTitle:c.title,baseline:challengeState.baseline,final:challengeState.final,completedAt:Date.now(),project:$('#firstProject')?.value||''};s.results.push(result);s.missions.push({day:0,completed:false,text:'Use the same method on one small useful list today.'})});schedule(firstSuccessSession(c),result);toast('First success saved. A quick reminder is scheduled.');route()});
  $('#projectForm')?.addEventListener('submit',e=>{e.preventDefault();const project=new FormData(e.target).get('project');update(s=>{s.firstSuccess=s.firstSuccess||{};s.firstSuccess.project=project});toast('Project saved')});
  $$('[data-review-form]').forEach(f=>f.onsubmit=e=>{e.preventDefault();const id=f.dataset.reviewForm,item=get().reviews.find(x=>x.id===id);if(!item)return;const recall=scoreOrderedRecall(item.material,$(`[data-review-answer="${id}"]`).value);scoreReview(id,recall.accuracy);const target=$(`#review-result-${id}`);if(target)target.innerHTML=`<div class="reveal-panel material"><h3>${recall.accuracy}% recalled</h3><p>${recall.correct} correct · ${recall.omitted} omitted · ${recall.orderErrors} order errors</p><p><strong>Source, now revealed:</strong></p><ol>${item.material.map(x=>`<li>${escapeHTML(displayReviewItem(x))}</li>`).join('')}</ol></div>`;const button=$('button',f);if(button)button.disabled=true;toast('Review scored and next interval updated.')});
  $$('[data-score]').forEach(b=>b.onclick=()=>{scoreReview(b.dataset.score,+$(`[data-review-score="${b.dataset.score}"]`).value);route()});
  $$('[data-review]').forEach(b=>b.onclick=()=>{const[t,id]=b.dataset.review.split(':');action(id,t);route()});
  $('#addPalace')?.addEventListener('click',()=>{const name=prompt('Palace name');if(name)update(s=>s.palaces.push({name,routeDescription:'Describe the fixed route',locations:[]}));route()});
  $$('[data-add-locus]').forEach(b=>b.onclick=()=>{update(s=>s.palaces[+b.dataset.addLocus].locations.push({name:'New location',description:'',feature:''}));route()});
  $$('[data-del-locus]').forEach(b=>b.onclick=()=>{const[p,i]=b.dataset.delLocus.split(':').map(Number);if(confirm('Delete this location?'))update(s=>s.palaces[p].locations.splice(i,1));route()});
  $$('[data-locus]').forEach(el=>el.onchange=()=>{const[p,i]=el.dataset.locus.split(':').map(Number);update(s=>s.palaces[p].locations[i].name=el.value)});
  $$('[data-duplicate]').forEach(b=>b.onclick=()=>{update(s=>s.palaces.push({...structuredClone(s.palaces[+b.dataset.duplicate]),name:s.palaces[+b.dataset.duplicate].name+' copy'}));route()});
  $$('[data-reverse]').forEach(b=>b.onclick=()=>alert(get().palaces[+b.dataset.reverse].locations.map(x=>x.name).reverse().join(' → ')));
  $$('[data-export-palace]').forEach(b=>b.onclick=()=>download('palace.json',JSON.stringify(get().palaces[+b.dataset.exportPalace],null,2)));
  $$('[data-major]').forEach(el=>el.onchange=()=>update(s=>s.majorSystem[+el.dataset.major].userImage=el.value));
  $('#majorCsv')?.addEventListener('click',()=>download('major-system.csv','number,sounds,image\n'+get().majorSystem.map(x=>`${x.number},"${x.sounds}","${(x.userImage||x.defaultImage).replaceAll('"','""')}"`).join('\n'),'text/csv'));
  $('#majorTest')?.addEventListener('click',()=>{const x=get().majorSystem[Math.floor(Math.random()*100)],ans=prompt(`What peg image is ${x.number}?`);alert(normalAnswer(ans)===normalAnswer(x.userImage||x.defaultImage)?'Correct — number to peg strengthened.':`Repair it: ${x.number} is ${x.userImage||x.defaultImage}`)});
  $('#majorReverseTest')?.addEventListener('click',()=>{const x=get().majorSystem[Math.floor(Math.random()*100)],peg=x.userImage||x.defaultImage,ans=prompt(`What number is ${peg}?`);alert(normalAnswer(ans)===normalAnswer(x.number)?'Correct — peg to number strengthened.':`Repair it: ${peg} is ${x.number}`)});
  $$('[data-scene-note]').forEach(el=>el.onchange=()=>update(s=>s.majorSystem[+el.dataset.sceneNote].sceneNote=el.value));
  $$('[data-speak-peg]').forEach(b=>b.onclick=()=>speakText(b.dataset.speakPeg));
  $$('[data-narrate]').forEach(b=>b.onclick=()=>{const scene=sceneByNumber(b.dataset.narrate);if(scene) speakText(scene.shortNarration||scene.shortSpokenMnemonic||scene.pegWord)});
  $$('[data-sfx]').forEach(b=>b.onclick=()=>toast('Sound-effect files are pending; imagine the listed sounds for now.'));
  $$('[data-major-card] details').forEach(d=>d.addEventListener('toggle',()=>{if(d.open){navigator.vibrate?.(18);d.closest('.major-cell')?.classList.add('impact');setTimeout(()=>d.closest('.major-cell')?.classList.remove('impact'),360)}}));
  $('#genericForm')?.addEventListener('submit',e=>{e.preventDefault();const type=e.target.dataset.type,obj=Object.fromEntries(new FormData(e.target));update(s=>s[type].push(obj));route()});
  $$('[data-delete-generic]').forEach(b=>b.onclick=()=>{const[t,i]=b.dataset.deleteGeneric.split(':');if(confirm('Delete this entry?'))update(s=>s[t].splice(+i,1));route()});
  $('#contractForm')?.addEventListener('submit',e=>{e.preventDefault();save({contract:Object.fromEntries(new FormData(e.target))});toast('Contract saved')});
  $('#exportJson')?.addEventListener('click',()=>download(`memory-mastery-${new Date().toISOString().slice(0,10)}.json`,JSON.stringify(get(),null,2)));
  $('#resultsCsv')?.addEventListener('click',()=>download('daily-results.csv','day,date,type,technique,accuracy,correct,incorrect,omitted,orderErrors\n'+get().results.map(r=>[r.day,new Date(r.date).toISOString(),r.type,r.technique,r.accuracy,r.correct,r.incorrect,r.omitted,r.orderErrors].map(v=>`"${String(v).replaceAll('"','""')}"`).join(',')).join('\n'),'text/csv'));
  $('#importJson')?.addEventListener('change',async e=>{try{const d=JSON.parse(await e.target.files[0].text());if(confirm('Import will replace current local data. Export a backup first. Continue?')){replace(d);applyDesignOverrides();route();toast('Backup imported')}}catch(err){alert(err.message)}});
  $('#reset')?.addEventListener('click',()=>{if(confirm('Permanently erase all local Memory Mastery data?')){reset();location.reload()}});
  $('#themeSetting')?.addEventListener('click',toggleTheme);
  $('#colorTheme')?.addEventListener('change',e=>{update(s=>s.profile.colorTheme=e.target.value);applyTheme();toast('Colour theme saved')});
  $('#uiStyle')?.addEventListener('change',e=>{update(s=>s.profile.uiStyle=e.target.value);applyTheme();toast('Layout saved')});
  $('#googleSignIn')?.addEventListener('click',startGoogleSignIn);
  $('#phoneAuthForm')?.addEventListener('submit',async e=>{e.preventDefault();try{await startPhoneSignIn($('#phoneNumber').value.trim())}catch(err){alert(`Phone sign-in failed: ${err.message}`)}});
  $('#phoneCodeForm')?.addEventListener('submit',async e=>{e.preventDefault();try{await finishPhoneSignIn($('#phoneCode').value.trim())}catch(err){alert(`Verification failed: ${err.message}`)}});
}

function speakText(text){if(!text)return; if('speechSynthesis' in window){speechSynthesis.cancel();speechSynthesis.speak(new SpeechSynthesisUtterance(text))}else toast(text)}
function badges(){const badge=$('#dueBadge');if(!badge)return;const count=due().length;badge.textContent=count;badge.hidden=count===0;badge.setAttribute('aria-label',count===1?'1 review due':`${count} reviews due`)}
function applyTheme(){const p=get().profile;document.body.classList.toggle('dark',p.theme==='dark');document.body.dataset.theme=p.colorTheme||'pastelPaper';document.body.dataset.ui=p.uiStyle||'smartpaper'}
const DESIGN_OVERRIDE_PROPERTIES={
  '--content':'max-width',
  '--space-3':'margin',
  '--space-4':'margin',
  '--space-5':'margin',
  '--radius-m':'border-radius',
  '--radius-l':'border-radius',
  '--accent':'color',
  '--accent-strong':'color',
  '--paper':'color',
  '--surface':'color',
  '--ink':'color',
  '--muted':'color'
};
function validDesignOverride(token,value){
  if(!Object.hasOwn(DESIGN_OVERRIDE_PROPERTIES,token)||typeof value!=='string')return false;
  const clean=value.trim();
  return clean.length>0&&clean.length<=80&&!/[;{}@\\]|\/\*/.test(clean)&&CSS.supports(DESIGN_OVERRIDE_PROPERTIES[token],clean);
}
function applyDesignOverrides(){
  let style=document.querySelector('#designOverrides');
  if(!style){style=document.createElement('style');style.id='designOverrides';document.head.append(style)}
  const overrides=get().designOverrides||{};
  const declarations=Object.entries(overrides).filter(([token,value])=>validDesignOverride(token,value)).map(([token,value])=>`${token}:${value.trim()}`).join(';');
  style.textContent=declarations?`:root,body,body.dark,body[data-theme],body.dark[data-theme]{${declarations}}`:'';
}
function toggleTheme(){update(s=>s.profile.theme=s.profile.theme==='dark'?'light':'dark');applyTheme()}
let cloudSaveTimer;async function queueCloudSave(){if(!configured())return;const user=await currentFirebaseUser();if(!user)return;clearTimeout(cloudSaveTimer);cloudSaveTimer=setTimeout(()=>saveCloudState(user.uid,get()).catch(e=>console.warn('Cloud autosave failed',e)),900)}
async function initialiseAuth(){if(!configured())return;try{await watchAuthState(async user=>{signedInEmail=user?.email||'';const archiveOwner=signedInEmail.toLowerCase()===ARCHIVE_OWNER_EMAIL;document.body.classList.toggle('owner-archive', archiveOwner);archiveOwner?sessionStorage.setItem('memoryMasteryArchiveOwner','1'):sessionStorage.removeItem('memoryMasteryArchiveOwner');const button=$('#authButton');if(button)button.textContent=user?'Sign out':'Sign in';if(!user)return;const local=get(), cloud=await loadCloudState(user.uid);if(cloud){const merged=mergeBackups(local,cloud);replace(merged);cleanupReviews();await saveCloudState(user.uid,get());applyTheme();applyDesignOverrides();route();toast('Device and cloud progress combined.')}else{await saveCloudState(user.uid,local);toast('Guest progress saved to your account.')}})}catch(e){console.warn('Firebase auth unavailable',e)}}
async function handleAuth(){if(!configured())return alert('Add Firebase web configuration in js/firebase.js first. Guest mode is fully available.');location.hash='#settings';setTimeout(()=>$('#authPanel')?.scrollIntoView({behavior:'smooth',block:'start'}),0);toast('Choose Google or phone sign-in in Settings.')}
async function startGoogleSignIn(){if(!configured())return alert('Add Firebase web configuration in js/firebase.js first.');try{const user=(await signInWithGoogle()).user;toast(`Signed in as ${user.displayName||user.email||'Google user'}. Sync is checking for existing progress.`)}catch(e){if(e.code==='auth/popup-closed-by-user')return;alert(`Google sign-in failed: ${e.message}`)}}
function phoneAuthMessage(error){if(error?.code==='auth/operation-not-allowed'||/region|sms|country/i.test(error?.message||''))return 'Phone sign-in is not available for this region yet. Use Google sign-in for now, and ask the developer to enable your country/region in Firebase Authentication SMS settings.';return error?.message||'Phone sign-in failed.'}
async function startPhoneSignIn(phoneNumber){try{phoneConfirmation=await signInWithPhone(phoneNumber);$('#phoneCodeForm').hidden=false;$('#phoneCode')?.focus();toast('Verification code sent.')}catch(error){throw Error(phoneAuthMessage(error))}}
async function finishPhoneSignIn(code){const user=(await confirmPhoneCode(phoneConfirmation,code)).user;toast(`Signed in as ${user.phoneNumber||'phone user'}. Sync is checking for existing progress.`)}
$('#theme').onclick=toggleTheme;
$('#authButton').onclick=async()=>{const signedIn=$('#authButton').textContent==='Sign out';if(signedIn){await signOutGoogle();toast('Signed out. Guest data remains on this device.');$('#authButton').textContent='Sign in'}else await handleAuth()};
$('#modal .close').onclick=()=>$('#modal').close();
boot().catch(e=>{$('#main').innerHTML=`<h1>Could not start</h1><p>${escapeHTML(e.message)}</p>`});
